@using Microsoft.AspNetCore.Identity
@using sv_773a81232d5d4f08904e80ad02e25ac1.Data

@inject UserManager<ApplicationUser> UserManager

<PageTitle>Employee Directory</PageTitle>

<h1>Employee Directory</h1>
<p class="text-muted">Accessible to all authenticated employees.</p>

@if (employees is null)
{
    <p><em>Loading directory...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Name</th>
                <th>Email</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var employee in employees)
            {
                <tr>
                    <td>@employee.FullName</td>
                    <td>@employee.Email</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ApplicationUser>? employees;

    protected override async Task OnInitializedAsync()
    {
        await Task.CompletedTask;
        employees = UserManager.Users.OrderBy(u => u.FullName).ToList();
    }
}

